import{_ as d,o as r,c as a,ae as o}from"./chunks/framework.BeMCGcrk.js";const u=JSON.parse('{"title":"📉 见底信号监测日报 | 2026-06-23","description":"","frontmatter":{},"headers":[],"relativePath":"blog/2026-06-23-review-bottom-signals.md","filePath":"blog/2026-06-23-review-bottom-signals.md"}'),e={name:"blog/2026-06-23-review-bottom-signals.md"};function h(n,t,l,s,i,b){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="📉-见底信号监测日报-2026-06-23" tabindex="-1">📉 见底信号监测日报 | 2026-06-23 <a class="header-anchor" href="#📉-见底信号监测日报-2026-06-23" aria-label="Permalink to &quot;📉 见底信号监测日报 | 2026-06-23&quot;">​</a></h1><blockquote><p>收盘后撰写 | 数据来源：腾讯财经、东方财富、博查搜索</p></blockquote><hr><h2 id="今日行情速览" tabindex="-1">今日行情速览 <a class="header-anchor" href="#今日行情速览" aria-label="Permalink to &quot;今日行情速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指数/品种</th><th>收盘/最新价</th><th>涨跌幅</th></tr></thead><tbody><tr><td>上证指数</td><td>4153.59</td><td>-</td></tr><tr><td>A股全天成交额</td><td><strong>预计超 3.7 万亿</strong>（午盘已破 1 万亿）</td><td>较上日缩量</td></tr><tr><td>恒科ETF (513180)</td><td>0.559</td><td>-3.95%</td></tr><tr><td>小米集团 (01810)</td><td>22.68 HKD</td><td>-4.38%</td></tr><tr><td>阿里 (09988)</td><td>99.30 HKD</td><td>-3.50%</td></tr><tr><td>贵州茅台 (600519)</td><td>1222.45</td><td>-1.53%</td></tr><tr><td>五粮液 (000858)</td><td>74.76</td><td>-2.34%</td></tr></tbody></table><hr><h2 id="六大见底信号评估" tabindex="-1">六大见底信号评估 <a class="header-anchor" href="#六大见底信号评估" aria-label="Permalink to &quot;六大见底信号评估&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>信号</th><th>监测指标</th><th>当前状态</th><th>评分</th></tr></thead><tbody><tr><td>①</td><td>成交地量</td><td>今日成交 vs 近20日均</td><td>预计超 3.7 万亿，连续第 41 个交易日破 2.5 万亿，<strong>非地量</strong></td><td>❌</td></tr><tr><td>②</td><td>估值极端低位</td><td>恒科成分股 PE</td><td>小米 PE 27.4，阿里 PE 16.2，<strong>估值合理偏低但非极端</strong></td><td>⚠️</td></tr><tr><td>③</td><td>强势股补跌</td><td>白酒茅台/五粮液走势</td><td>茅台 -1.53%，五粮液 -2.34%，<strong>白酒持续下行中</strong></td><td>✅</td></tr><tr><td>④</td><td>无人谈股</td><td>新增开户/搜索热度</td><td>5月新开户 <strong>276.53 万户</strong>，环比 +11%，<strong>有增量资金进场</strong></td><td>❌</td></tr><tr><td>⑤</td><td>机构割肉</td><td>消费→AI调仓新闻</td><td>消费/医药公募<strong>集中漂移</strong>至 AI/半导体，<strong>机构确实在调仓</strong></td><td>✅</td></tr><tr><td>⑥</td><td>国家队增持</td><td>港股增持信号</td><td>恒指 6/12 涨 2%，恒科涨 1.6%，国家队信号<strong>存在但不明确</strong></td><td>⚠️</td></tr></tbody></table><hr><h2 id="信号解读" tabindex="-1">信号解读 <a class="header-anchor" href="#信号解读" aria-label="Permalink to &quot;信号解读&quot;">​</a></h2><h3 id="_1-成交地量-—-❌-未出现" tabindex="-1">① 成交地量 — ❌ 未出现 <a class="header-anchor" href="#_1-成交地量-—-❌-未出现" aria-label="Permalink to &quot;① 成交地量 — ❌ 未出现&quot;">​</a></h3><blockquote><p>&quot;沪深两市成交额连续第 <strong>41 个交易日</strong> 突破 2.5 万亿元&quot;</p></blockquote><p>今日午盘成交已破 1 万亿，全天预计超 3.7 万亿。这恰恰说明市场活跃度依然较高，并非情绪冰点。6 月 18 日曾出现 3.33 万亿成交，连续放量 3 日，市场短期有资金博弈。</p><p><strong>结论：地量信号未触发。</strong></p><hr><h3 id="_2-估值极端低位-—-⚠️-部分满足" tabindex="-1">② 估值极端低位 — ⚠️ 部分满足 <a class="header-anchor" href="#_2-估值极端低位-—-⚠️-部分满足" aria-label="Permalink to &quot;② 估值极端低位 — ⚠️ 部分满足&quot;">​</a></h3><table tabindex="0"><thead><tr><th>品种</th><th>PE</th><th>股价</th><th>近期表现</th></tr></thead><tbody><tr><td>小米</td><td>27.4</td><td>22.68 HKD</td><td>近一年 -42%，近一月 -13.6%</td></tr><tr><td>阿里</td><td>16.2</td><td>99.30 HKD</td><td>近一年 -30%，近一月 -9.2%</td></tr><tr><td>恒科ETF</td><td>—</td><td>0.559</td><td>近一年 -34.8%，近六月 -9.4%</td></tr></tbody></table><p>小米从高点回调已超 40%，PE 从高点 60+ 降至 27，泡沫大幅消化。阿里 PE 16 倍在互联网平台中属合理偏低水位。恒科ETF 从高位 0.896 跌至 0.559，跌幅 37.7%。</p><p><strong>结论：估值进入偏低区间，但未到极端低位，可左侧布局。</strong></p><hr><h3 id="_3-强势股补跌-—-✅-进行中" tabindex="-1">③ 强势股补跌 — ✅ 进行中 <a class="header-anchor" href="#_3-强势股补跌-—-✅-进行中" aria-label="Permalink to &quot;③ 强势股补跌 — ✅ 进行中&quot;">​</a></h3><ul><li><strong>茅台</strong>：今日 -1.53%，近一年 -11.2%，现价 1222.45，距高点 1850 跌约 34%</li><li><strong>五粮液</strong>：今日 -2.34%，近一年 -29.4%，现价 74.76，距高点 208 跌超 60%</li></ul><p>中国酒业协会 6 月 18 日报告显示：<strong>86.7% 酒企利润下滑，近 7 成认为下半年继续下行</strong>。消费端 6·18 亮眼（终端消费回暖）与资本市场的持续寒意形成&quot;冰火两重天&quot;。</p><p><strong>结论：强势股补跌仍在进行，符合底部特征。</strong></p><hr><h3 id="_4-无人谈股-—-❌-信号不符" tabindex="-1">④ 无人谈股 — ❌ 信号不符 <a class="header-anchor" href="#_4-无人谈股-—-❌-信号不符" aria-label="Permalink to &quot;④ 无人谈股 — ❌ 信号不符&quot;">​</a></h3><blockquote><p>上交所数据：2026 年 5 月 A 股新开户 <strong>276.53 万户</strong>，环比 4 月（249.13 万户）增长约 <strong>11%</strong>，2026 年累计新开 <strong>1729.67 万户</strong>。</p></blockquote><p>新股民持续进场，市场并未出现&quot;无人谈股&quot;的冷清景象。5 月数据仍在攀升，说明情绪未到冰点。</p><p><strong>结论：情绪指标不支持底部判断。</strong></p><hr><h3 id="_5-机构割肉-—-✅-调仓进行时" tabindex="-1">⑤ 机构割肉 — ✅ 调仓进行时 <a class="header-anchor" href="#_5-机构割肉-—-✅-调仓进行时" aria-label="Permalink to &quot;⑤ 机构割肉 — ✅ 调仓进行时&quot;">​</a></h3><blockquote><p>财联社 6 月 6 日报道：消费、医药主题公募<strong>大幅漂移</strong>，重仓 AI/半导体/光模块等科技股，集中在 <strong>2026 年 5-6 月</strong>。</p></blockquote><p>中泰证券 6 月配置策略明确建议：</p><blockquote><p>&quot;适当减仓，科技内部切换至高赔率资产，关注必需消费&quot;</p></blockquote><p>这意味着机构正在<strong>从消费/医药撤出，转向科技内部切换</strong>。割肉行为确实存在，但方向是调仓而非空仓。</p><p><strong>结论：机构在结构性调仓，逻辑上支持部分消费股见底。</strong></p><hr><h3 id="_6-国家队增持-—-⚠️-信号存在但不明确" tabindex="-1">⑥ 国家队增持 — ⚠️ 信号存在但不明确 <a class="header-anchor" href="#_6-国家队增持-—-⚠️-信号存在但不明确" aria-label="Permalink to &quot;⑥ 国家队增持 — ⚠️ 信号存在但不明确&quot;">​</a></h3><p>近期港股有所反弹：</p><ul><li>6 月 12 日：恒指涨 2%，恒科涨 1.6%</li><li>6 月 9 日：恒科涨超 1%</li><li>6 月 11 日：恒指/恒科转涨</li></ul><p>SpaceX 6 月 12 日上市，恒生指数公司将其纳入恒生港美科技指数，带来短期催化。但国家队明确增持信号（如 ETF 申购、汇金/社保公告）暂未出现在搜索结果中。</p><p><strong>结论：港股有资金托底迹象，但未观察到明确的国家队增持公告。</strong></p><hr><h2 id="综合研判" tabindex="-1">综合研判 <a class="header-anchor" href="#综合研判" aria-label="Permalink to &quot;综合研判&quot;">​</a></h2><table tabindex="0"><thead><tr><th>信号</th><th>状态</th></tr></thead><tbody><tr><td>成交地量</td><td>❌ 未出现</td></tr><tr><td>估值低位</td><td>⚠️ 合理偏低</td></tr><tr><td>强势股补跌</td><td>✅ 进行中</td></tr><tr><td>无人谈股</td><td>❌ 新开户活跃</td></tr><tr><td>机构割肉</td><td>✅ 结构性调仓</td></tr><tr><td>国家队增持</td><td>⚠️ 迹象存在但不明确</td></tr></tbody></table><p><strong>当前市场特征更像&quot;结构性底部&quot;而非&quot;全面底部&quot;。</strong> 消费/白酒持续出清，恒科估值回归合理，但成交活跃、增量资金进场、全面性的恐慌抛售尚未出现。</p><p>右侧信号观察：</p><ul><li>白酒能否出现加速赶底（单日跌幅 &gt;5%）</li><li>成交额是否跌破 2.5 万亿（打破连续 41 日纪录）</li><li>国家队是否有明确增持公告</li></ul><hr><h2 id="操作建议-个人记录-不构成投资建议" tabindex="-1">操作建议（个人记录，不构成投资建议） <a class="header-anchor" href="#操作建议-个人记录-不构成投资建议" aria-label="Permalink to &quot;操作建议（个人记录，不构成投资建议）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方向</th><th>信号</th><th>建议</th></tr></thead><tbody><tr><td>港股恒科</td><td>估值合理，技术面未企稳</td><td>等待右侧，不盲目抄底</td></tr><tr><td>白酒</td><td>补跌进行中</td><td>观察茅台能否企稳 1200 下方</td></tr><tr><td>A股科技</td><td>机构调仓方向</td><td>关注 AI/半导体内部切换机会</td></tr></tbody></table><hr><p><em>数据来源：腾讯财经实时行情（15:06）、博查搜索（市场情绪新闻）</em><em>本日记录个人观察与思考，不构成投资建议。</em></p>',53)])])}const p=d(e,[["render",h]]);export{u as __pageData,p as default};
